const c = $json.checkpoint || {};
const updates = [];
if (String(c.pain_reported || '').toLowerCase().includes('knee')) {
  updates.push('Reduce impact activities');
  updates.push('Replace running with walking/cycling');
  updates.push('Add 10-minute mobility routine');
}
if ((c.energy || 3) <= 2) updates.push('Lower training intensity by 20% for next session');
if ((c.sleep_quality || 3) <= 2) updates.push('Focus on sleep hygiene and earlier workout timing');
if ((c.meal_adherence || '').toLowerCase() === 'low') updates.push('Simplify meals and add prep-friendly options');
return [{ json: { ...$json, adaptive_updates: updates, next_day_plan_adjusted: updates.length > 0 } }];
